import type { InitAnswers } from "./wizard.js";

const HEADER = `# ~/.isotopes/isotopes.yaml
# Generated by \`isotopes init\`. See isotopes.example.yaml in the repo
# (https://github.com/GhostComplex/isotopes) for the full set of options.
`;

const PROVIDER_SKIP = `# provider:
#   type: github-copilot
#   defaultModel: claude-opus-4.7
#   apiKey: \${GITHUB_TOKEN}
`;

function renderProvider(answers: InitAnswers): string {
  if (answers.llm !== "ghc-proxy" || !answers.ghcProxy) return PROVIDER_SKIP;
  const { baseUrl, apiKey, model } = answers.ghcProxy;
  return `provider:
  type: anthropic
  baseUrl: ${baseUrl}
  apiKey: ${apiKey}
  defaultModel: ${model}
`;
}

function renderAgents(answers: InitAnswers): string {
  const lines = [`agents:`, `  - id: main`];
  if (answers.claude === "claude") {
    lines.push(`  - id: coding`, `    runner: claude`);
  }
  return lines.join("\n") + "\n";
}

function renderChannels(answers: InitAnswers): string {
  if (answers.channel !== "discord" || !answers.discord) return "";
  const { token, dmPolicy, dmUserId, groupPolicy, groupAllowlist } = answers.discord;

  const dmBlock = dmPolicy === "allowlist" && dmUserId
    ? `        dmAccess:
          policy: allowlist
          allowlist:
            - "${dmUserId}"
`
    : `        dmAccess:
          policy: disabled
`;

  let groupBlock: string;
  if (groupPolicy === "allowlist" && groupAllowlist?.length) {
    const guildIds = new Set<string>();
    const channelIds: string[] = [];
    for (const entry of groupAllowlist) {
      const [guildId, channelId] = entry.split("/");
      guildIds.add(guildId);
      if (channelId) channelIds.push(channelId);
    }
    const guildLines = [...guildIds].map((id) => `            - "${id}"`).join("\n");
    const channelLines = channelIds.map((id) => `            - "${id}"`).join("\n");
    groupBlock = `        groupAccess:
          policy: allowlist
          guildAllowlist:
${guildLines}
`;
    if (channelLines.length > 0) {
      groupBlock += `          channelAllowlist:
${channelLines}
`;
    }
  } else {
    groupBlock = `        groupAccess:
          policy: ${groupPolicy}
`;
  }

  return `
channels:
  discord:
    accounts:
      main:
        token: ${token}
        defaultAgentId: main
${dmBlock}${groupBlock}        threadBindings:
          enabled: true
`;
}

export function renderConfig(answers: InitAnswers): string {
  return [HEADER, renderProvider(answers), renderAgents(answers), renderChannels(answers)]
    .filter((s) => s.length > 0)
    .join("\n");
}
